PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "llm_metadata" (
                id INTEGER PRIMARY KEY,
                file_id INTEGER UNIQUE NOT NULL,
                
                -- Core Analysis Flags
                AI_ANALYZED BOOLEAN DEFAULT 0,
                LLM_ANALYZED BOOLEAN DEFAULT 0,
                AI_ANALYZED_DATE TEXT,
                LLM_ANALYSIS_DATE TEXT,
                
                -- Audio Analysis (AI calculated)
                AI_BPM REAL,
                AI_ENERGY REAL,
                AI_KEY TEXT,
                AI_MODE TEXT,
                AI_TIME_SIGNATURE INTEGER,
                AI_DANCEABILITY REAL,
                AI_VALENCE REAL,
                AI_ACOUSTICNESS REAL,
                AI_INSTRUMENTALNESS REAL,
                AI_LIVENESS REAL,
                AI_SPEECHINESS REAL,
                AI_LOUDNESS REAL,
                AI_MOOD TEXT,
                AI_CONFIDENCE REAL,
                
                -- LLM Analysis
                LLM_GENRE TEXT,
                LLM_SUBGENRES TEXT,
                LLM_ERA TEXT,
                LLM_STYLE_PERIOD TEXT,
                LLM_DESCRIPTION TEXT,
                LLM_CONTEXT TEXT,
                LLM_ENERGY_LEVEL TEXT,
                LLM_OCCASIONS TEXT,
                
                -- Lyrics Analysis
                LLM_LYRICS_ANALYSIS TEXT,
                LLM_LYRICS_THEME TEXT,
                LLM_LYRICS_MOOD TEXT,
                LLM_LYRICS_LANGUAGE TEXT,
                LLM_EXPLICIT_CONTENT BOOLEAN DEFAULT 0,
                LLM_STORYTELLING TEXT,
                
                -- DJ & Performance
                LLM_DJ_NOTES TEXT,
                LLM_MIXING_NOTES TEXT,
                LLM_MIXING_KEYS TEXT,
                LLM_COMPATIBLE_GENRES TEXT,
                
                -- Production & Style
                LLM_PRODUCTION_STYLE TEXT,
                LLM_INSTRUMENTS TEXT,
                LLM_VOCAL_STYLE TEXT,
                LLM_ENERGY_DESCRIPTION TEXT,
                
                -- Relationships & Recommendations
                LLM_SIMILAR_ARTISTS TEXT,
                LLM_RECOMMENDATIONS TEXT,
                LLM_MUSICAL_INFLUENCE TEXT,
                
                -- Classification Flags
                LLM_IS_COMPILATION BOOLEAN DEFAULT 0,
                LLM_IS_REMIX BOOLEAN DEFAULT 0,
                LLM_IS_COVER BOOLEAN DEFAULT 0,
                LLM_IS_LIVE BOOLEAN DEFAULT 0,
                
                -- Quality & Validation
                LLM_CONFIDENCE_SCORE REAL,
                LLM_VALIDATION_NOTES TEXT,
                LLM_WARNINGS TEXT,
                
                -- System Metadata
                llm_version TEXT,
                analysis_timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP, ESSENTIA_PROCESSED INTEGER DEFAULT 0, ESSENTIA_DATE TIMESTAMP, LLM_CAMELOT_KEY TEXT, LLM_REAL_YEAR INTEGER, LLM_YEAR_SOURCE TEXT, LLM_ISRC_PARSED TEXT, LLM_LYRICS_SOURCE TEXT, LLM_SENTIMENT REAL, LLM_EMOTIONS TEXT, LLM_KEYWORDS TEXT, LLM_COHERENCE_SCORE REAL, LLM_COHERENCE_NOTES TEXT, LLM_TOPICS_MAIN TEXT, LLM_TOPICS_SECONDARY TEXT, LLM_HOOK_CANDIDATES TEXT, LLM_REPEATED_PHRASES TEXT, LLM_CULTURAL_REFERENCES TEXT, LLM_NARRATIVE_PERSPECTIVE TEXT, LLM_NARRATIVE_TIME TEXT, LLM_STRUCTURE TEXT, LLM_NAMED_ENTITIES TEXT, LLM_CALL_AND_RESPONSE BOOLEAN DEFAULT 0, LLM_CONTAINS_SHOUTS BOOLEAN DEFAULT 0, LLM_EXPLICITNESS_LEVEL TEXT, LLM_CONTENT_WARNINGS TEXT, LLM_SINGALONG_INDEX REAL, LLM_CHANTABILITY REAL, LLM_JUSTIFICATION TEXT, ESSENTIA_LOUDNESS_LUFS REAL, ESSENTIA_EXTRACT_STRATEGY TEXT, ESSENTIA_WINDOWS_USED TEXT, ESSENTIA_NOTES TEXT, GPT4_TOKENS_USED INTEGER, GPT4_PROCESSING_TIME REAL, GPT4_ESTIMATED_COST REAL, GPT4_MODEL_VERSION TEXT, GPT4_COMPLETE_ANALYSIS TEXT, AI_TEMPO_CONFIDENCE REAL DEFAULT 0.0, AI_KEY_CONFIDENCE REAL DEFAULT 0.0, extract_strategy TEXT, windows_used TEXT, notes TEXT,
                
                FOREIGN KEY (file_id) REFERENCES audio_files(id)
            );
COMMIT;
